import React, { useState } from "react";
import { Plus, X } from "lucide-react";

export function ScheduleManager() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const weekDays = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-white">Class Schedule</h1>
        <button onClick={() => setIsModalOpen(true)} className="bg-[#39FF14] text-black px-6 py-3 rounded-lg font-bold flex items-center gap-2">
          <Plus size={20} /> Create New Class
        </button>
      </div>

      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl overflow-x-auto">
        <div className="grid grid-cols-8 border-b border-[#2a2a2a] bg-[#121212]">
          <div className="p-4 border-r border-[#2a2a2a] text-xs text-gray-500">Time</div>
          {weekDays.map(day => (
            <div key={day} className="p-4 text-center font-bold text-sm">{day}</div>
          ))}
        </div>
        {[...Array(12)].map((_, i) => (
          <div key={i} className="grid grid-cols-8 border-b border-[#2a2a2a] h-20">
            <div className="p-2 border-r border-[#2a2a2a] text-[10px] text-gray-600">{i+8}:00</div>
            {[...Array(7)].map((_, j) => (
              <div key={j} className="border-r border-[#2a2a2a] last:border-r-0 hover:bg-white/5 transition-colors"></div>
            ))}
          </div>
        ))}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4">
          <div className="bg-[#1a1a1a] border border-[#2a2a2a] w-full max-w-lg rounded-2xl p-6 relative">
            <button onClick={() => setIsModalOpen(false)} className="absolute top-4 right-4"><X /></button>
            <h2 className="text-xl font-bold mb-6">Create New Class</h2>
            <form className="space-y-4">
              <input className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-lg" placeholder="Class Name" />
              <input type="date" className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-lg" />
              <button className="w-full bg-[#39FF14] text-black font-bold py-3 rounded-lg mt-4">Create</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
